package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import com.github.javaparser.ast.expr.FieldAccessExpr;
import com.github.javaparser.ast.expr.Expression;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.out.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        Path sourcePath = Paths.get(sourceDir);

        if (!Files.exists(sourcePath)) {
            System.out.println("Source directory does not exist: " + sourceDir);
            System.exit(1);
        }

        // Process all Java files in the directory
        Files.walk(sourcePath)
            .filter(path -> path.toString().endsWith(".java"))
            .forEach(Main::processJavaFile);
    }

    private static void processJavaFile(Path filePath) {
        try {
            CompilationUnit cu = StaticJavaParser.parse(filePath.toFile());

            // Apply transformation to replace the broken TLS imports and usage
            new TLSImportRemovalVisitor().visit(cu, null);
            new TLSUsageRemovalVisitor().visit(cu, null);

            // Save the modified file
            cu.save(filePath.toFile());
        } catch (Exception e) {
            System.err.println("Error processing " + filePath + ": " + e.getMessage());
            e.printStackTrace();
        }
    }

    // Visitor to remove the TLS imports
    private static class TLSImportRemovalVisitor extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(com.github.javaparser.ast.imports.ImportDeclaration importDecl, Void arg) {
            super.visit(importDecl, arg);
            if (importDecl.getNameAsString().startsWith("org.bouncycastle.crypto.tls")) {
                importDecl.remove();
            }
        }
    }

    // Visitor to replace TLS usage with appropriate replacements
    private static class TLSUsageRemovalVisitor extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(MethodCallExpr methodCall, Void arg) {
            super.visit(methodCall, arg);

            // Replace TlsFatalAlert constructor calls
            if (methodCall.getNameAsString().equals("TlsFatalAlert")) {
                // This would likely be a constructor call, but we need to handle it appropriately
                // For now, we'll just mark this for manual review
                System.out.println("Found TlsFatalAlert usage in: " + methodCall.toString());
            }
        }

        @Override
        public void visit(FieldAccessExpr fieldAccess, Void arg) {
            super.visit(fieldAccess, arg);

            // Replace AlertDescription references
            if (fieldAccess.getNameAsString().equals("AlertDescription")) {
                System.out.println("Found AlertDescription usage in: " + fieldAccess.toString());
            }
        }
    }
}

